var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 이상한 사람이네요.","JPN":"あなたはおかしな人ですね。","ENG":"You're an odd person.","TWN":"你是個奇怪的人呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"한때 반목했던 사람을 구태여 곁에 두고, 다른 직원분들과 마찬가지의 태도로 대하시다니.","JPN":"かつで反目していた人をそばにおいて、他の職員たちと同じく接するとは。","ENG":"You keep someone who was once your enemy by your side and treat them in the same way as your other employees","TWN":"竟然把曾經與你背道而馳的人留在身邊，還試圖像對待其他職員一樣對待他們。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 꽤나 연기에 소질이 있으시군요.","JPN":"ふふ、なかなかの演技力です。","ENG":"Haha. You seem to have a knack for acting.","TWN":"呵呵，看來您還真有表演的天賦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기회가 된다면, 한 번쯤은 연습 상대가 되어드리죠.","JPN":"機会があるなら、一度は練習相手になってあげましょう。","ENG":"If the opportunity arises, I shall be your practice partner.","TWN":"如果有機會的話，我可以做您的練習對手。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어떤 각본이라도, 어떤 설정이라도 좋으니까요.","JPN":"どんな脚本でも、どんな設定でもいいですから。","ENG":"Any script or setting will be fine for me.","TWN":"無論是什麼劇本，什麼設定都可以。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"인생이라는 무대 위에서 사람들은 저마다 배역을 갖고 있다고 하죠.","JPN":"人生という舞台の上で、人はそれぞれの配役を持っていると言われています。","ENG":"Everyone has a role to play on this stage called life.","TWN":"在名為人生的舞臺上，每個人都有自己的角色。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"누구든 그 배역을 스스로 결정할 수는 없어요.","JPN":"誰しもその役割を自分で決めることはできません。","ENG":"But no one is allowed to decide their own roles.","TWN":"要扮演誰，要成為誰，每個人都無法自己決定。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로. 세계가 안배한 운명에 따라, 움직일 뿐.","JPN":"すべては脚本どおりに。世界が定めた運命に従い、動くだけ。","ENG":"Everything according to the script. I follow the fate arranged by the world.","TWN":"一切都將按照劇本進行。我們只是按照世界安排的命運行動而已。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요, 저는 한때 백조를 꿈꿨답니다.","JPN":"そう、私は昔白鳥を夢見ていました。","ENG":"Yes. I once dreamt of becoming a swan.","TWN":"是的，我曾經夢想成為一隻天鵝。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 어떤 시련이든 클라이맥스에 이르러 스포트라이트를 받으며 문제를 해결하는 사람.","JPN":"どんな試練でもクライマックスに至ってスポットライトを浴びながら問題を解決する人。","ENG":"Someone who reaches the climax of any ordeal, receives the spotlight, and solves the problem.","TWN":"一個無論遇到什麼考驗，都會在高潮時刻成為焦點，解決問題的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"백조는 그 자체만으로도 아름답고 우아한 존재니까요.","JPN":"白鳥はそれ自体が美しく優雅な存在ですから。","ENG":"A swan itself is a beautiful and elegant creature.","TWN":"因為天鵝本身就是美麗而優雅的存在。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 지난 무대에서도……. 이번 무대에서도 제게 주어진 배역은 그런 역할이 아니더군요.","JPN":"でも、この前の舞台でも……今回の舞台でも、私に与えられた配役はそのようなものではなかったのです。","ENG":"But even during my previous performance... or even this one, it seems I wasn't given that role.","TWN":"但不論是在上一個舞臺上……還是這次的舞臺，分配給我的都不是那樣的角色。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 아마도 이 세계에서 그 배역을 맡은 사람은…….","JPN":"そしてたぶんこの世界でその役割を担当した人は……","ENG":"And perhaps the person who got this role in this world is...","TWN":"或許在這個世界中，擔任那個角色的人便是……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"좋아요, 당신과 전속계약을 맺도록 하죠.","JPN":"いいでしょう、あなたと専属契約します。","ENG":"Very well. I will sign an exclusive contract with you.","TWN":"好，我會和你簽訂專屬契約的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 가장 가까운 곳에서, 당신이 결국 무엇을 이루게 되는지 보고 싶어졌으니까…….","JPN":"あなたの一番近くで、あなたが結局は何を成し遂げることになるのか見たくなりましたから……","ENG":"Because I would like to see what you will accomplish from right next to you.","TWN":"因為我想在你身邊，親眼見證你最終能成就什麼……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 어쩌면…….","JPN":"そして、もしかしたら……","ENG":"And maybe...","TWN":"而且，或許……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 가슴 속에 응어리진 감정을 풀어낼 수 있을지도 모르니까…….","JPN":"この胸の中に蟠っている感情を解消することができるかもしれないから……","ENG":"I might be able to release these feelings that are stuck in my heart...","TWN":"或許能解開我胸中鬱結了許久的情感……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼, 사인을 부탁드려도 될까요?","JPN":"では、サインをお願いしてもいいですか？","ENG":"Then, could you sign it now?","TWN":"那麼，可以請您簽個名嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"팬이니까요. 당신의.","JPN":"ファンですから。あなたの。","ENG":"I'm actually a fan of yours.","TWN":"因為我是你的粉絲。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};